/* ──── Gestión de deudas: créditos con proveedores y pagos ──── */
function GestionDeudas({ data, add, upd, del, session, onClose }) {
  const [tab, setTab] = useState("debemos");
  const [showForm, setShowForm] = useState(false);
  const [detalle, setDetalle] = useState(null);
  const F0 = { concepto: "", proveedor: "", monto: "", fecha: today() };
  const [form, setForm] = useState(F0);
  const [abono, setAbono] = useState({ id: null, monto: "" });

  const crearCredito = () => {
    if (!form.concepto || !form.monto) { alert("Falta concepto o monto"); return; }
    add("creditos", {
      id: `cr${Date.now()}`, concepto: form.concepto, proveedor: form.proveedor,
      monto: parseFloat(form.monto) || 0, fecha: form.fecha, estado: "activo", abonos: [],
      registradoPor: { rol: session.role, id: session.id, nombre: session.nombre },
    });
    setForm(F0); setShowForm(false);
  };

  const aplicarAbono = cr => {
    const m = parseFloat(abono.monto) || 0;
    if (m <= 0) { alert("Indica el monto del abono"); return; }
    const nuevoAbono = { id: `ab${Date.now()}`, fecha: today(), monto: m };
    const nuevosAbonos = [...(cr.abonos || []), nuevoAbono];
    const totalAbonado = nuevosAbonos.reduce((s, a) => s + a.monto, 0);
    upd("creditos", { ...cr, abonos: nuevosAbonos, estado: totalAbonado >= cr.monto ? "pagado" : "activo" });
    setAbono({ id: null, monto: "" });
  };

  const creditos = [...(data.creditos || [])].sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));

  if (detalle) {
    const cr = (data.creditos || []).find(c => c.id === detalle);
    if (!cr) { setDetalle(null); return null; }
    const sc = saldoCredito(cr);
    return (
      <div>
        <div className="top-bar">
          <button className="btn-ghost" onClick={() => setDetalle(null)}>‹</button>
          <h2>Crédito</h2>
        </div>
        <div className="section-pad">
          <div className="card">
            <div className="flex-b mb-2">
              <div className="font-syne font-bold" style={{ fontSize: 16 }}>{cr.concepto}</div>
              <span className={`badge badge-${cr.estado === "pagado" ? "green" : "gold"}`}>{cr.estado}</span>
            </div>
            <div className="confirm-row"><span className="cr-label">Proveedor</span><span className="cr-val">{cr.proveedor || "—"}</span></div>
            <div className="confirm-row"><span className="cr-label">Monto original</span><span className="cr-val">{fmt(cr.monto)}</span></div>
            <div className="confirm-row"><span className="cr-label">Abonado</span><span className="cr-val">{fmt(sc.abonado)}</span></div>
            <div className="confirm-row"><span className="cr-label">Saldo</span><span className="cr-val" style={{ color: "var(--red)" }}>{fmt(sc.saldo)}</span></div>
          </div>
          {cr.estado === "activo" && (
            <div className="card ab">
              <div className="card-title">Registrar abono</div>
              <div className="inp-row">
                <input type="number" className="inp" placeholder="Monto del abono" value={abono.id === cr.id ? abono.monto : ""} onChange={e => setAbono({ id: cr.id, monto: e.target.value })} />
                <button className="btn btn-accent btn-sm" style={{ flex: "0 0 auto" }} onClick={() => aplicarAbono(cr)}>✓ Abonar</button>
              </div>
            </div>
          )}
          <div className="card">
            <div className="card-title">Historial de abonos</div>
            {(cr.abonos || []).length === 0 && <div className="text-muted text-sm">Sin abonos todavía</div>}
            {(cr.abonos || []).map(ab => (
              <div key={ab.id} className="list-item">
                <div className="li-icon">💵</div>
                <div className="li-body"><div className="li-title">{fmt(ab.monto)}</div><div className="li-sub">{ab.fecha}</div></div>
                <button className="btn-ghost" style={{ padding: 2, fontSize: 13, color: "var(--red)" }}
                  onClick={() => { if (confirm("¿Eliminar este abono?")) upd("creditos", { ...cr, abonos: cr.abonos.filter(x => x.id !== ab.id), estado: "activo" }); }}>🗑</button>
              </div>
            ))}
          </div>
          <button className="btn btn-danger" onClick={() => { if (confirm("¿Eliminar este crédito y su historial?")) { del("creditos", cr.id); setDetalle(null); } }}>🗑 Eliminar crédito</button>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="top-bar">
        <button className="btn-ghost" onClick={onClose}>‹</button>
        <h2 style={{ flex: 1 }}>Deudas 🏦</h2>
        <button className="btn btn-accent btn-sm" onClick={() => setShowForm(v => !v)}>{showForm ? "✕" : "+ Crédito"}</button>
      </div>
      <div className="section-pad">
        {showForm && (
          <div className="card ab">
            <div className="card-title">Nuevo crédito con proveedor</div>
            <div className="form-group"><label className="form-label">Concepto</label><input className="inp" placeholder="Ej: Compra de fertilizante a crédito" value={form.concepto} onChange={e => setForm(f => ({ ...f, concepto: e.target.value }))} /></div>
            <div className="form-group"><label className="form-label">Proveedor</label><input className="inp" value={form.proveedor} onChange={e => setForm(f => ({ ...f, proveedor: e.target.value }))} /></div>
            <div className="form-group"><label className="form-label">Monto ($)</label><input type="number" className="inp" value={form.monto} onChange={e => setForm(f => ({ ...f, monto: e.target.value }))} /></div>
            <div className="form-group"><label className="form-label">Fecha</label><input type="date" className="inp" value={form.fecha} onChange={e => setForm(f => ({ ...f, fecha: e.target.value }))} /></div>
            <button className="btn btn-accent" onClick={crearCredito}>Guardar crédito</button>
          </div>
        )}
        <div className="text-xs text-muted mb-3" style={{ paddingLeft: 4 }}>Créditos con proveedores. Toca uno para registrar abonos o ver su saldo.</div>
        {creditos.length === 0 && <div className="text-muted text-sm" style={{ textAlign: "center", padding: "32px 0" }}>Sin créditos registrados</div>}
        {creditos.map(cr => {
          const sc = saldoCredito(cr);
          return (
            <div key={cr.id} className="card" style={{ cursor: "pointer" }} onClick={() => setDetalle(cr.id)}>
              <div className="flex-b mb-1">
                <div className="font-bold">{cr.concepto}</div>
                <span className={`badge badge-${cr.estado === "pagado" ? "green" : "gold"}`}>{cr.estado}</span>
              </div>
              <div className="text-sm text-muted">{cr.proveedor || "—"} · {cr.fecha}</div>
              <div className="flex-b mt-2">
                <span className="text-xs text-muted">Saldo por pagar</span>
                <span className="font-bold" style={{ color: sc.saldo > 0 ? "var(--red)" : "var(--safe)" }}>{fmt(sc.saldo)}</span>
              </div>
              <div className="progress mt-1"><div className="progress-fill green" style={{ width: `${cr.monto > 0 ? (sc.abonado / cr.monto) * 100 : 0}%` }} /></div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ════════════ MIGRACIÓN INICIAL A LA NUBE ════════════ */

/* ════════════ MIGRACIÓN INICIAL DESDE EXCEL ════════════ */
/* Permite descargar una plantilla, llenarla, y subirla a Supabase + dejarla en el navegador. */
function SubirCatalogos({ data, setData, session, onClose }) {
  const [paso, setPaso] = useState("inicio"); // inicio | revision | subiendo | hecho | error
  const [archivoLeido, setArchivoLeido] = useState(null);
  const [colecciones, setColecciones] = useState(null);
  const [validacion, setValidacion] = useState(null);
  const [sqlGenerado, setSqlGenerado] = useState("");
  const [resumen, setResumen] = useState(null);
  const [errorMsg, setErrorMsg] = useState("");
  const fileRef = useRef(null);

  const descargar = () => {
    try { generarPlantilla(); }
    catch (e) { alert("No se pudo descargar la plantilla: " + (e.message || e)); }
  };

  const cargarArchivo = async (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    try {
      const datos = await leerExcel(file);
      const cols = excelAColecciones(datos);
      const val = validar(cols);
      setArchivoLeido(file.name);
      setColecciones(cols);
      setValidacion(val);
      setSqlGenerado(generarSQLCuentas(cols.cuentas));
      setPaso("revision");
    } catch (err) {
      setErrorMsg(err.message || "Error al leer el archivo");
      setPaso("error");
    }
  };

  // Mezcla los catálogos del Excel con los datos locales del navegador.
  // Por cada catálogo que vino lleno en el Excel: reemplaza el catálogo local.
  // Los catálogos que no vinieron en el Excel se quedan como estaban.
  const aplicarLocalmente = (cols) => {
    setData(prev => {
      const next = { ...prev };
      CATALOGOS.forEach(tabla => {
        const registros = cols[tabla] || [];
        if (registros.length > 0) next[tabla] = registros;
      });
      return next;
    });
  };

  const subir = async () => {
    if (!colecciones) return;
    setPaso("subiendo");
    try {
      const r = {};
      // 1. Subir a Supabase
      for (const tabla of CATALOGOS) {
        const registros = colecciones[tabla] || [];
        if (registros.length === 0) { r[tabla] = { ok: true, cantidad: 0, omitido: true }; continue; }
        try {
          const n = await subirColeccion(tabla, registros);
          r[tabla] = { ok: true, cantidad: n };
        } catch (e) {
          r[tabla] = { ok: false, error: e.message };
        }
      }
      // 2. Mezclar también localmente para que la app los vea de inmediato
      try { aplicarLocalmente(colecciones); }
      catch (e) { console.warn("No se pudo aplicar localmente:", e); }

      setResumen(r);
      const huboError = Object.values(r).some(x => x.ok === false);
      setPaso(huboError ? "error" : "hecho");
    } catch (e) {
      setErrorMsg(e.message || "Error desconocido");
      setPaso("error");
    }
  };

  const copiarSQL = () => {
    navigator.clipboard.writeText(sqlGenerado)
      .then(() => alert("SQL copiado. Pégalo en Supabase → SQL Editor → Run."))
      .catch(() => alert("No se pudo copiar. Selecciona el texto y cópialo manualmente."));
  };

  // Resumen de cuántos registros encontró en el Excel
  const cuentaSi = arr => arr && arr.length || 0;
  const totalRegistros = colecciones
    ? CATALOGOS.reduce((s, c) => s + cuentaSi(colecciones[c]), 0) + cuentaSi(colecciones.cuentas)
    : 0;

  return (
    <div>
      <div className="top-bar">
        <button className="btn-ghost" onClick={onClose}>‹</button>
        <h2>Subir a la nube ☁️</h2>
      </div>
      <div className="section-pad">

        {paso === "inicio" && (
          <>
            <div className="card" style={{ background: "rgba(126,200,50,.06)", border: "1px solid rgba(126,200,50,.2)" }}>
              <div className="card-title">¿Cómo funciona?</div>
              <div className="text-sm" style={{ lineHeight: 1.6 }}>
                1. Descarga la plantilla de Excel.<br/>
                2. Llénala con los datos reales del rancho (cuentas, parcelas, trabajadores, etc.).<br/>
                3. Súbela aquí. Los datos quedan guardados en la nube <strong>y disponibles en la app de inmediato</strong>.
              </div>
            </div>

            <div className="card">
              <div className="card-title">Paso 1: descargar plantilla</div>
              <div className="text-sm text-muted mb-3" style={{ lineHeight: 1.5 }}>
                Excel con 8 hojas (Instrucciones + 7 catálogos), con ejemplos y encabezados ya listos.
              </div>
              <button className="btn btn-outline" onClick={descargar}>📥 Descargar plantilla</button>
            </div>

            <div className="card">
              <div className="card-title">Paso 2: cargar plantilla llena</div>
              <div className="text-sm text-muted mb-3" style={{ lineHeight: 1.5 }}>
                Cuando tengas el Excel con tus datos, súbelo aquí.
              </div>
              <input ref={fileRef} type="file" accept=".xlsx,.xls"
                style={{ display: "none" }} onChange={cargarArchivo} />
              <button className="btn btn-accent" onClick={() => fileRef.current && fileRef.current.click()} disabled={!supabaseListo}>
                {supabaseListo ? "📤 Elegir archivo Excel" : "La nube no está configurada"}
              </button>
            </div>
          </>
        )}

        {paso === "revision" && colecciones && validacion && (
          <>
            <div className="card">
              <div className="card-title">Archivo: {archivoLeido}</div>
              <div className="text-sm text-muted">Esto es lo que encontré:</div>
            </div>

            <div className="card">
              <div className="card-title">Resumen</div>
              <div className="confirm-row"><span className="cr-label">Cuentas de administración</span><span className="cr-val">{cuentaSi(colecciones.cuentas)}</span></div>
              {CATALOGOS.map(c => (
                <div key={c} className="confirm-row">
                  <span className="cr-label">{c}</span>
                  <span className="cr-val">{cuentaSi(colecciones[c])}</span>
                </div>
              ))}
              <div className="confirm-row" style={{ borderTop: "2px solid var(--accent)", marginTop: 8, paddingTop: 10 }}>
                <span className="cr-label" style={{ fontWeight: 700 }}>TOTAL</span>
                <span className="cr-val" style={{ fontWeight: 700, color: "var(--accent)" }}>{totalRegistros}</span>
              </div>
            </div>

            {validacion.errores.length > 0 && (
              <div className="alert alert-red">
                <span className="alert-icon">❌</span>
                <div className="alert-body">
                  <div className="alert-title">Errores ({validacion.errores.length})</div>
                  <div className="alert-desc">Corrige estos problemas antes de subir:</div>
                  <ul style={{ margin: "8px 0 0 16px", padding: 0 }}>
                    {validacion.errores.map((e, i) => <li key={i} className="text-sm">{e}</li>)}
                  </ul>
                </div>
              </div>
            )}

            {validacion.advertencias.length > 0 && (
              <div className="alert alert-gold">
                <span className="alert-icon">⚠️</span>
                <div className="alert-body">
                  <div className="alert-title">Advertencias</div>
                  <ul style={{ margin: "4px 0 0 16px", padding: 0 }}>
                    {validacion.advertencias.map((a, i) => <li key={i} className="text-sm">{a}</li>)}
                  </ul>
                </div>
              </div>
            )}

            {cuentaSi(colecciones.cuentas) > 0 && (
              <div className="card" style={{ background: "rgba(125,180,255,.08)", border: "1px solid rgba(125,180,255,.3)" }}>
                <div className="card-title">🔐 Cuentas: paso especial</div>
                <div className="text-sm" style={{ lineHeight: 1.5, marginBottom: 10 }}>
                  La app no puede crear cuentas de administración directamente (por seguridad). Te genera un código SQL que tienes que pegar en Supabase:
                </div>
                <ol style={{ marginLeft: 18, fontSize: 13, lineHeight: 1.6 }}>
                  <li>Copia el código de abajo.</li>
                  <li>Ve a Supabase → SQL Editor → New query.</li>
                  <li>Pega el código y dale Run.</li>
                  <li>Listo: las cuentas quedan creadas en Supabase Auth.</li>
                </ol>
                <button className="btn btn-outline btn-sm mt-2" onClick={copiarSQL}>📋 Copiar código SQL</button>
                <textarea readOnly value={sqlGenerado} style={{ width: "100%", height: 120, marginTop: 10, fontFamily: "monospace", fontSize: 11, padding: 8, borderRadius: 6, border: "1px solid var(--border)", background: "var(--bg)" }} />
              </div>
            )}

            <div className="gap-row mt-3">
              <button className="btn btn-outline" style={{ flex: 1 }} onClick={() => setPaso("inicio")}>Cancelar</button>
              <button className="btn btn-accent" style={{ flex: 1 }} onClick={subir} disabled={!validacion.ok}>
                {validacion.ok ? "Subir catálogos →" : "Corrige errores primero"}
              </button>
            </div>
          </>
        )}

        {paso === "subiendo" && (
          <div className="card" style={{ textAlign: "center", padding: "32px 16px" }}>
            <div style={{ fontSize: 48 }}>☁️</div>
            <div className="font-bold mt-2">Subiendo a la nube...</div>
            <div className="text-sm text-muted mt-1">Esto puede tomar unos segundos. No cierres esta pantalla.</div>
          </div>
        )}

        {paso === "hecho" && (
          <>
            <div className="alert alert-green">
              <span className="alert-icon">✅</span>
              <div className="alert-body">
                <div className="alert-title">¡Listo!</div>
                <div className="alert-desc">Los catálogos se subieron a la nube y ya están disponibles en la app para usarlos.</div>
              </div>
            </div>
            {cuentaSi(colecciones.cuentas) > 0 && (
              <div className="alert alert-gold">
                <span className="alert-icon">🔐</span>
                <div className="alert-body">
                  <div className="alert-title">No olvides las cuentas</div>
                  <div className="alert-desc">Si todavía no pegaste el SQL de cuentas en Supabase, hazlo ahora. Sin eso, los administradores no podrán entrar.</div>
                </div>
              </div>
            )}
            <div className="card">
              <div className="card-title">Resumen</div>
              {Object.entries(resumen || {}).map(([c, r]) => (
                <div key={c} className="confirm-row">
                  <span className="cr-label">{c}</span>
                  <span className="cr-val" style={{ color: r.ok ? "var(--safe)" : "var(--red)" }}>
                    {r.ok ? (r.omitido ? "— sin datos" : `✓ ${r.cantidad}`) : `✗ ${r.error}`}
                  </span>
                </div>
              ))}
            </div>
            <button className="btn btn-outline" onClick={onClose}>Cerrar</button>
          </>
        )}

        {paso === "error" && (
          <>
            <div className="alert alert-red">
              <span className="alert-icon">❌</span>
              <div className="alert-body">
                <div className="alert-title">Hubo un problema</div>
                <div className="alert-desc">{errorMsg || "Algo salió mal. Revisa el detalle abajo."}</div>
              </div>
            </div>
            {resumen && (
              <div className="card">
                <div className="card-title">Detalle</div>
                {Object.entries(resumen).map(([c, r]) => (
                  <div key={c} className="confirm-row">
                    <span className="cr-label">{c}</span>
                    <span className="cr-val" style={{ color: r.ok ? "var(--safe)" : "var(--red)" }}>
                      {r.ok ? `✓ ${r.cantidad}` : `✗ ${r.error}`}
                    </span>
                  </div>
                ))}
              </div>
            )}
            <button className="btn btn-outline" onClick={() => setPaso("inicio")}>Volver a intentar</button>
          </>
        )}

      </div>
    </div>
  );
}

/* ════════════ MODAL: COMPLETAR INDICACIÓN ════════════ */
/* Se abre cuando alguien marca una indicación como hecha.
   Pide horas, cantidad real aplicada (si era insumo), notas.
   Al guardar: crea la actividad, descuenta inventario, carga costo a parcela. */
function CompletarIndicacionModal({ tarea, data, add, upd, setInv, session, onClose, onCompletado }) {
  const tieneInsumo = !!tarea.insumoId;
  const insumo = tieneInsumo ? (data.inventario || []).find(i => i.id === tarea.insumoId) : null;
  const [fecha, setFecha] = useState(today());
  const [horas, setHoras] = useState("");
  const [cantidadInsumo, setCantidadInsumo] = useState(tarea.cantidadInsumo || "");
  const [notas, setNotas] = useState("");
  const [guardando, setGuardando] = useState(false);

  const parcela = data.parcelas.find(p => p.id === tarea.parcelaId);
  const cantidadNum = parseFloat(cantidadInsumo) || 0;
  const costoEstimado = tieneInsumo && insumo ? (insumo.costo_unit || 0) * cantidadNum : 0;

  const guardar = () => {
    if (tieneInsumo && cantidadNum <= 0) {
      alert("Indica cuánto insumo se aplicó realmente.");
      return;
    }
    if (tieneInsumo && insumo && cantidadNum > (insumo.existencia || 0)) {
      if (!confirm(`Solo hay ${insumo.existencia} ${insumo.unidad || ""} en inventario y vas a descontar ${cantidadNum}. ¿Continuar de todas formas?`)) return;
    }
    setGuardando(true);
    try {
      const r = completarIndicacion({
        tarea, data, add, upd, setInv, session,
        datosActividad: { fecha, horas, notas, cantidadInsumo: cantidadNum },
      });
      if (onCompletado) onCompletado(r);
      onClose();
    } catch (e) {
      alert("No se pudo registrar: " + (e.message || e));
      setGuardando(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-sheet" onClick={e => e.stopPropagation()}>
        <div className="flex-b mb-3">
          <h3 style={{ margin: 0, fontSize: 18 }}>Completar indicación</h3>
          <button className="btn-ghost" onClick={onClose} style={{ fontSize: 20 }}>✕</button>
        </div>
        <div className="card" style={{ background: "rgba(126,200,50,.06)", border: "1px solid rgba(126,200,50,.2)" }}>
          <div className="font-bold">{tarea.titulo}</div>
          {parcela && <div className="text-sm text-muted mt-1">📍 {parcela.nombre}{parcela.cultivo ? " · " + parcela.cultivo : ""}</div>}
          {tarea.detalle && <div className="text-sm mt-2">{tarea.detalle}</div>}
        </div>
        <div className="text-xs text-muted mb-3" style={{ marginTop: 12 }}>
          Esto va a crear el registro de la actividad real con sus horas y, si aplica, descontar el insumo del inventario y cargar el costo a la parcela.
        </div>
        <div className="form-group">
          <label className="form-label">¿Cuándo se hizo?</label>
          <input type="date" className="inp" value={fecha} onChange={e => setFecha(e.target.value)} max={today()} />
        </div>
        <div className="form-group">
          <label className="form-label">Horas trabajadas (opcional)</label>
          <input type="number" step="0.25" className="inp" placeholder="Ej: 3" value={horas} onChange={e => setHoras(e.target.value)} />
        </div>
        {tieneInsumo && insumo && (
          <>
            <div className="form-group">
              <label className="form-label">Cantidad de {insumo.nombre} aplicada ({insumo.unidad || "unid"})</label>
              <input type="number" step="0.01" className="inp" placeholder="Ej: 50" value={cantidadInsumo} onChange={e => setCantidadInsumo(e.target.value)} />
              <div className="text-xs text-muted mt-1">Inventario actual: {fmtN(insumo.existencia || 0)} {insumo.unidad || ""}</div>
            </div>
            {cantidadNum > 0 && (
              <div className="alert alert-blue mb-3">
                <span className="alert-icon">💰</span>
                <div className="alert-body">
                  <div className="alert-desc">Esto descontará {fmtN(cantidadNum)} {insumo.unidad || ""} del inventario y cargará {fmt(costoEstimado)} a la parcela.</div>
                </div>
              </div>
            )}
          </>
        )}
        <div className="form-group">
          <label className="form-label">Observaciones (opcional)</label>
          <textarea className="inp" placeholder="Notas del trabajo realizado..." value={notas} onChange={e => setNotas(e.target.value)} />
        </div>
        <div className="gap-row" style={{ marginTop: 16 }}>
          <button className="btn btn-outline" style={{ flex: 1 }} onClick={onClose} disabled={guardando}>Cancelar</button>
          <button className="btn btn-accent" style={{ flex: 1.5 }} onClick={guardar} disabled={guardando}>
            {guardando ? "Guardando..." : "✓ Marcar como hecha"}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ════════════ SOLICITUDES DE COMPRA ════════════ */
/* Cualquiera crea solicitudes itemizadas. Finanzas/admin/encargados las gestionan.
   Botón de WhatsApp para cotizar con proveedores. */
function SolicitudesCompra({ data, add, upd, del, setInv, aplicarLote, session, onClose }) {
  const rol = session.role;
  const puedeGestionar = ["admin", "finanzas", "encargado", "dueno"].includes(rol);
  const puedeConfirmarCompra = ["admin", "finanzas"].includes(rol);
  const [showForm, setShowForm] = useState(false);
  const [verSolic, setVerSolic] = useState(null); // solicitud abierta en detalle
  const [filtro, setFiltro] = useState("todas"); // todas | pendiente | cotizando | comprada
  const [confirmarCompra, setConfirmarCompra] = useState(null); // solicitud que se está convirtiendo en compra

  // Formulario de nueva solicitud
  const F0 = { paraCuando: "", notas: "", items: [] };
  const [form, setForm] = useState(F0);
  const [itemTmp, setItemTmp] = useState({ insumoId: "", nombre: "", cantidad: "", unidad: "", nota: "" });

  // Mis solicitudes (las que creé) o todas (si gestiono)
  const solicitudes = (data.solicitudes_compra || [])
    .filter(s => puedeGestionar || (s.creadaPor && s.creadaPor.id === session.id))
    .filter(s => filtro === "todas" || s.estado === filtro)
    .sort((a, b) => (b.fecha || "").localeCompare(a.fecha || ""));

  const agregarItem = () => {
    const nombre = itemTmp.insumoId
      ? (data.inventario.find(i => i.id === itemTmp.insumoId)?.nombre || itemTmp.nombre)
      : itemTmp.nombre.trim();
    if (!nombre) { alert("Escribe o elige un producto."); return; }
    const inv = itemTmp.insumoId ? data.inventario.find(i => i.id === itemTmp.insumoId) : null;
    setForm(f => ({
      ...f,
      items: [...f.items, {
        id: `it${Date.now()}`,
        insumoId: itemTmp.insumoId || null,
        nombre,
        cantidad: itemTmp.cantidad || "",
        unidad: itemTmp.unidad || (inv?.unidad || ""),
        nota: itemTmp.nota.trim(),
      }],
    }));
    setItemTmp({ insumoId: "", nombre: "", cantidad: "", unidad: "", nota: "" });
  };

  const quitarItem = (id) => setForm(f => ({ ...f, items: f.items.filter(x => x.id !== id) }));

  const guardar = () => {
    if (form.items.length === 0) { alert("Agrega al menos un producto a la solicitud."); return; }
    add("solicitudes_compra", {
      fecha: today(),
      paraCuando: form.paraCuando,
      notas: form.notas,
      items: form.items,
      estado: "pendiente",
      creadaPor: { id: session.id, nombre: session.nombre || "", rol },
    });
    setForm(F0);
    setShowForm(false);
  };

  const cambiarEstado = (s, nuevoEstado) => upd("solicitudes_compra", { ...s, estado: nuevoEstado });

  const badgeColor = (estado) => estado === "comprada" ? "green" : estado === "cotizando" ? "gold" : estado === "cancelada" ? "red" : "blue";
  const estadoLabel = (estado) => ({ pendiente: "Pendiente", cotizando: "Cotizando", comprada: "Comprada", cancelada: "Cancelada" }[estado] || estado);

  // ── Vista detalle de una solicitud ──
  if (verSolic) {
    const s = (data.solicitudes_compra || []).find(x => x.id === verSolic.id) || verSolic;
    return (
      <div>
        <div className="top-bar">
          <button className="btn-ghost" onClick={() => setVerSolic(null)}>‹</button>
          <h2>Solicitud de compra</h2>
        </div>
        <div className="section-pad">
          <div className="card">
            <div className="flex-b mb-2">
              <span className={`badge badge-${badgeColor(s.estado)}`}>{estadoLabel(s.estado)}</span>
              <span className="text-xs text-muted">{s.fecha}</span>
            </div>
            <div className="text-sm text-muted">Solicitó: {s.creadaPor?.nombre || "—"} ({s.creadaPor?.rol || "—"})</div>
            {s.paraCuando && <div className="text-sm mt-1">📅 Para: {s.paraCuando}</div>}
            {s.notas && <div className="text-sm mt-2" style={{ fontStyle: "italic" }}>{s.notas}</div>}
          </div>

          <div className="card">
            <div className="card-title">Productos ({s.items?.length || 0})</div>
            {(s.items || []).map((it, i) => (
              <div key={it.id || i} className="list-item">
                <div className="li-body">
                  <div className="li-title">{i + 1}. {it.nombre}</div>
                  <div className="li-sub">
                    {it.cantidad ? `${it.cantidad} ${it.unidad || ""}` : "cantidad sin especificar"}
                    {it.nota ? ` · ${it.nota}` : ""}
                  </div>
                </div>
              </div>
            ))}
          </div>

          {puedeGestionar && (
            <>
              <div className="card">
                <div className="card-title">📲 Cotizar por WhatsApp</div>
                <div className="text-sm text-muted mb-3">Manda la lista a un proveedor para pedir precio. Elige uno o mándalo genérico.</div>
                {(data.proveedores || []).length > 0 && (
                  <div style={{ marginBottom: 10 }}>
                    {(data.proveedores || []).map(pv => (
                      <a key={pv.id} className="btn btn-outline btn-sm mb-2" style={{ width: "100%", textDecoration: "none", display: "block" }}
                         href={urlWhatsAppCotizacion(s, pv)} target="_blank" rel="noopener noreferrer"
                         onClick={() => { if (s.estado === "pendiente") cambiarEstado(s, "cotizando"); }}>
                        📲 {pv.nombre}{pv.telefono ? "" : " (elegir contacto)"}
                      </a>
                    ))}
                  </div>
                )}
                <a className="btn btn-accent btn-sm" style={{ width: "100%", textDecoration: "none", display: "block" }}
                   href={urlWhatsAppCotizacion(s, null)} target="_blank" rel="noopener noreferrer"
                   onClick={() => { if (s.estado === "pendiente") cambiarEstado(s, "cotizando"); }}>
                  📲 Mandar genérico (elegir contacto)
                </a>
              </div>

              {puedeConfirmarCompra && s.estado !== "comprada" && s.estado !== "cancelada" && (
                <div className="card" style={{ background: "rgba(126,200,50,.06)", border: "1px solid rgba(126,200,50,.25)" }}>
                  <div className="card-title">✅ Registrar la compra</div>
                  <div className="text-sm text-muted mb-3">Cuando ya compraste estos productos, regístralo aquí: entrarán al inventario y se registrará el gasto en finanzas, todo de una vez.</div>
                  <button className="btn btn-accent" style={{ width: "100%" }} onClick={() => setConfirmarCompra(s)}>
                    Confirmar compra y mover inventario
                  </button>
                </div>
              )}

              {s.estado === "comprada" && (
                <div className="card" style={{ background: "rgba(126,200,50,.08)" }}>
                  <div className="text-sm" style={{ color: "var(--safe)", fontWeight: 700 }}>✓ Compra registrada</div>
                  <div className="text-xs text-muted mt-1">Los productos entraron al inventario y el gasto quedó en finanzas.</div>
                </div>
              )}

              <div className="card">
                <div className="card-title">Cambiar estado</div>
                <div className="gap-row" style={{ flexWrap: "wrap" }}>
                  {["pendiente", "cotizando", "cancelada"].map(est => (
                    <button key={est} className={`btn btn-sm ${s.estado === est ? "btn-accent" : "btn-outline"}`}
                            style={{ flex: "1 1 45%" }} onClick={() => cambiarEstado(s, est)}>
                      {estadoLabel(est)}
                    </button>
                  ))}
                </div>
                <div className="text-xs text-muted mt-2">El estado "comprada" se asigna al confirmar la compra arriba.</div>
              </div>

              <button className="btn btn-danger" onClick={() => { if (confirm("¿Borrar esta solicitud?")) { del("solicitudes_compra", s.id); setVerSolic(null); } }}>
                🗑 Borrar solicitud
              </button>
            </>
          )}
        </div>
        {confirmarCompra && (
          <ConfirmarCompraModal
            solicitud={confirmarCompra} data={data} add={add} upd={upd} setInv={setInv} aplicarLote={aplicarLote} session={session}
            onClose={() => setConfirmarCompra(null)}
            onHecho={() => { setConfirmarCompra(null); }}
          />
        )}
      </div>
    );
  }

  // ── Vista principal: lista + crear ──
  return (
    <div>
      <div className="top-bar">
        {onClose && <button className="btn-ghost" onClick={onClose}>‹</button>}
        <h2>Solicitudes de compra 🛒</h2>
      </div>
      <div className="section-pad">
        {!showForm && (
          <button className="btn btn-accent mb-3" style={{ width: "100%" }} onClick={() => setShowForm(true)}>
            + Nueva solicitud
          </button>
        )}

        {showForm && (
          <div className="card">
            <div className="card-title">Nueva solicitud de compra</div>

            <div className="form-group">
              <label className="form-label">¿Para cuándo se necesita? (opcional)</label>
              <input className="inp" placeholder="Ej: esta semana, antes del viernes..." value={form.paraCuando} onChange={e => setForm(f => ({ ...f, paraCuando: e.target.value }))} />
            </div>

            <div style={{ borderTop: "1px solid var(--border)", paddingTop: 12, marginTop: 4 }}>
              <div className="card-title">Agregar producto</div>
              <div className="form-group">
                <label className="form-label">Del inventario (opcional)</label>
                <select className="inp" value={itemTmp.insumoId} onChange={e => {
                  const inv = data.inventario.find(i => i.id === e.target.value);
                  setItemTmp(x => ({ ...x, insumoId: e.target.value, nombre: inv?.nombre || "", unidad: inv?.unidad || "" }));
                }}>
                  <option value="">— Escribir libre —</option>
                  {(data.inventario || []).map(i => <option key={i.id} value={i.id}>{i.emoji || "📦"} {i.nombre}</option>)}
                </select>
              </div>
              {!itemTmp.insumoId && (
                <div className="form-group">
                  <label className="form-label">Producto (texto libre)</label>
                  <input className="inp" placeholder="Ej: Urea, Glifosato, semilla..." value={itemTmp.nombre} onChange={e => setItemTmp(x => ({ ...x, nombre: e.target.value }))} />
                </div>
              )}
              <div className="gap-row">
                <div className="form-group" style={{ flex: 1 }}>
                  <label className="form-label">Cantidad</label>
                  <input type="number" className="inp" placeholder="0" value={itemTmp.cantidad} onChange={e => setItemTmp(x => ({ ...x, cantidad: e.target.value }))} />
                </div>
                <div className="form-group" style={{ flex: 1 }}>
                  <label className="form-label">Unidad</label>
                  <input className="inp" placeholder="kg, L, pza..." value={itemTmp.unidad} onChange={e => setItemTmp(x => ({ ...x, unidad: e.target.value }))} />
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Nota (opcional)</label>
                <input className="inp" placeholder="Marca, urgencia, detalle..." value={itemTmp.nota} onChange={e => setItemTmp(x => ({ ...x, nota: e.target.value }))} />
              </div>
              <button className="btn btn-outline btn-sm" style={{ width: "100%" }} onClick={agregarItem}>+ Agregar a la lista</button>
            </div>

            {form.items.length > 0 && (
              <div style={{ marginTop: 14 }}>
                <div className="card-title">Lista ({form.items.length})</div>
                {form.items.map((it, i) => (
                  <div key={it.id} className="list-item">
                    <div className="li-body">
                      <div className="li-title">{i + 1}. {it.nombre}</div>
                      <div className="li-sub">{it.cantidad ? `${it.cantidad} ${it.unidad || ""}` : "—"}{it.nota ? ` · ${it.nota}` : ""}</div>
                    </div>
                    <button className="btn btn-danger btn-sm" style={{ flex: "0 0 auto" }} onClick={() => quitarItem(it.id)}>✕</button>
                  </div>
                ))}
              </div>
            )}

            <div className="form-group" style={{ marginTop: 12 }}>
              <label className="form-label">Notas generales (opcional)</label>
              <textarea className="inp" placeholder="Cualquier comentario para quien gestione la compra..." value={form.notas} onChange={e => setForm(f => ({ ...f, notas: e.target.value }))} />
            </div>

            <div className="gap-row mt-2">
              <button className="btn btn-outline" style={{ flex: 1 }} onClick={() => { setForm(F0); setShowForm(false); }}>Cancelar</button>
              <button className="btn btn-accent" style={{ flex: 1.5 }} onClick={guardar}>Enviar solicitud</button>
            </div>
          </div>
        )}

        {!showForm && (
          <>
            {puedeGestionar && (
              <div className="tabs-pill mb-3">
                {[["todas", "Todas"], ["pendiente", "Pendientes"], ["cotizando", "Cotizando"], ["comprada", "Compradas"]].map(([v, lb]) => (
                  <button key={v} className={`tab-pill${filtro === v ? " active" : ""}`} onClick={() => setFiltro(v)}>{lb}</button>
                ))}
              </div>
            )}
            {solicitudes.length === 0 && <div className="text-muted text-sm" style={{ textAlign: "center", padding: "32px 0" }}>Sin solicitudes {filtro !== "todas" ? `(${estadoLabel(filtro).toLowerCase()})` : ""}</div>}
            {solicitudes.map(s => (
              <div key={s.id} className="card" style={{ cursor: "pointer" }} onClick={() => setVerSolic(s)}>
                <div className="flex-b mb-1">
                  <span className={`badge badge-${badgeColor(s.estado)}`}>{estadoLabel(s.estado)}</span>
                  <span className="text-xs text-muted">{s.fecha}</span>
                </div>
                <div className="font-bold">{s.items?.length || 0} producto(s)</div>
                <div className="text-sm text-muted" style={{ marginTop: 2 }}>
                  {(s.items || []).slice(0, 3).map(it => it.nombre).join(", ")}{(s.items?.length || 0) > 3 ? "..." : ""}
                </div>
                {puedeGestionar && <div className="text-xs text-muted" style={{ marginTop: 4 }}>Solicitó: {s.creadaPor?.nombre || "—"}</div>}
                {s.paraCuando && <div className="text-xs" style={{ color: "var(--accent)", marginTop: 2 }}>📅 {s.paraCuando}</div>}
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  );
}

/* ════════════ MODAL: CONFIRMAR COMPRA DE UNA SOLICITUD ════════════ */
/* Convierte una solicitud en compra real: cada item entra al inventario
   (subiendo existencia y recalculando costo promedio) y genera su egreso
   en finanzas. La solicitud queda marcada como "comprada". */
function ConfirmarCompraModal({ solicitud, data, add, upd, setInv, aplicarLote, session, onClose, onHecho }) {
  // Pre-llenar cada item de la solicitud con: insumo destino, cantidad y costo.
  // Si el item ya venía ligado a un insumo del inventario, se respeta.
  const [lineas, setLineas] = useState(() => (solicitud.items || []).map(it => {
    // Intentar adivinar el insumo por nombre si no trae insumoId
    let insumoId = it.insumoId || "";
    if (!insumoId) {
      const m = (data.inventario || []).find(i => i.nombre.toLowerCase() === (it.nombre || "").toLowerCase());
      if (m) insumoId = m.id;
    }
    return {
      idLinea: it.id || `l${Math.random()}`,
      insumoId: insumoId || "__nuevo__",
      nombreNuevo: insumoId ? "" : (it.nombre || ""),
      cat: "nutricion",
      unidad: it.unidad || "kg",
      cantidad: it.cantidad || "",
      costoTotal: "",
    };
  }));
  const [proveedor, setProveedor] = useState("");
  const [fecha, setFecha] = useState(today());
  const [guardando, setGuardando] = useState(false);

  const setLinea = (idLinea, campo, valor) => setLineas(ls => ls.map(l => l.idLinea === idLinea ? { ...l, [campo]: valor } : l));

  const totalCompra = lineas.reduce((s, l) => s + (parseFloat(l.costoTotal) || 0), 0);

  const confirmar = () => {
    // Validar
    for (const l of lineas) {
      const cant = parseFloat(l.cantidad) || 0;
      if (cant <= 0) { alert("Cada producto necesita una cantidad mayor a cero."); return; }
      if (l.insumoId === "__nuevo__" && !l.nombreNuevo.trim()) { alert("Escribe el nombre del insumo nuevo."); return; }
    }
    if (guardando) return;
    setGuardando(true);

    // Armar TODAS las operaciones en un solo lote (un solo re-render).
    const ops = [];
    const ts = Date.now();
    lineas.forEach((l, idx) => {
      const cant = parseFloat(l.cantidad) || 0;
      const costo = parseFloat(l.costoTotal) || 0;
      let insumoId = l.insumoId;
      let nombreInsumo = "";

      if (insumoId === "__nuevo__") {
        insumoId = `inv${ts}_${idx}`;
        nombreInsumo = l.nombreNuevo.trim();
        ops.push({ tipo: "add", sec: "inventario", item: {
          id: insumoId, nombre: nombreInsumo, cat: l.cat, unidad: l.unidad,
          existencia: cant, costo_unit: cant > 0 ? costo / cant : 0, minimo: 0, emoji: "🧪",
        }});
      } else {
        const inv = (data.inventario || []).find(i => i.id === insumoId);
        if (!inv) return;
        nombreInsumo = inv.nombre;
        const nuevaExist = (inv.existencia || 0) + cant;
        const nuevoCostoProm = nuevaExist > 0 ? ((inv.existencia || 0) * (inv.costo_unit || 0) + costo) / nuevaExist : 0;
        ops.push({ tipo: "upd", sec: "inventario", item: { ...inv, existencia: nuevaExist, costo_unit: nuevoCostoProm } });
      }

      if (costo > 0) {
        ops.push({ tipo: "add", sec: "egresos", item: {
          id: `e${ts}_${idx}`, fecha, concepto: `Compra: ${nombreInsumo}`, categoria: "insumos",
          monto: costo, proveedor, solicitudId: solicitud.id,
          registradoPor: { rol: session.role, id: session.id, nombre: session.nombre || "" },
        }});
      }
      ops.push({ tipo: "add", sec: "entradas_inv", item: {
        id: `ei${ts}_${idx}`, fecha, insumoId, cantidad: cant, costo_total: costo, proveedor, factura: "",
        concepto: "Compra desde solicitud",
      }});
    });

    // Marcar la solicitud como comprada (misma operación en lote)
    ops.push({ tipo: "upd", sec: "solicitudes_compra", item: {
      ...solicitud, estado: "comprada",
      compraInfo: { fecha, proveedor, total: totalCompra, confirmadaPor: { id: session.id, nombre: session.nombre || "" } },
    }});

    // Aplicar TODO de una vez (un solo render, sin bloqueo)
    aplicarLote(ops);

    alert("Compra registrada: los productos entraron al inventario y el gasto quedó en finanzas.");
    onHecho && onHecho();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "90vh", overflowY: "auto" }}>
        <div className="flex-b mb-3">
          <h3 style={{ margin: 0, fontSize: 18 }}>Confirmar compra</h3>
          <button className="btn-ghost" onClick={onClose} style={{ fontSize: 20 }}>✕</button>
        </div>
        <div className="text-sm text-muted mb-3">Revisa y ajusta lo que realmente se compró. Al confirmar, entra al inventario y se registra el gasto.</div>

        {lineas.map((l, idx) => {
          const itemOrig = (solicitud.items || [])[idx];
          return (
            <div key={l.idLinea} className="card" style={{ padding: "12px 14px" }}>
              <div className="font-bold text-sm mb-2">{itemOrig?.nombre || `Producto ${idx + 1}`}</div>
              <div className="form-group">
                <label className="form-label">¿A qué insumo del inventario?</label>
                <select className="inp" value={l.insumoId} onChange={e => setLinea(l.idLinea, "insumoId", e.target.value)}>
                  {(data.inventario || []).map(i => <option key={i.id} value={i.id}>{i.emoji || "📦"} {i.nombre}</option>)}
                  <option value="__nuevo__">➕ Insumo nuevo</option>
                </select>
              </div>
              {l.insumoId === "__nuevo__" && (
                <div className="inp-row">
                  <div className="form-group" style={{ flex: 2 }}><label className="form-label">Nombre nuevo</label><input className="inp" value={l.nombreNuevo} onChange={e => setLinea(l.idLinea, "nombreNuevo", e.target.value)} /></div>
                  <div className="form-group" style={{ flex: 1 }}><label className="form-label">Unidad</label>
                    <select className="inp" value={l.unidad} onChange={e => setLinea(l.idLinea, "unidad", e.target.value)}>
                      {["kg", "L", "ton", "saco", "pieza", "caja"].map(u => <option key={u}>{u}</option>)}
                    </select>
                  </div>
                </div>
              )}
              <div className="inp-row">
                <div className="form-group" style={{ flex: 1 }}><label className="form-label">Cantidad</label><input type="number" className="inp" value={l.cantidad} onChange={e => setLinea(l.idLinea, "cantidad", e.target.value)} /></div>
                <div className="form-group" style={{ flex: 1 }}><label className="form-label">Costo total ($)</label><input type="number" className="inp" value={l.costoTotal} onChange={e => setLinea(l.idLinea, "costoTotal", e.target.value)} /></div>
              </div>
            </div>
          );
        })}

        <div className="inp-row">
          <div className="form-group" style={{ flex: 1 }}><label className="form-label">Proveedor</label><input className="inp" value={proveedor} onChange={e => setProveedor(e.target.value)} /></div>
          <div className="form-group" style={{ flex: 1 }}><label className="form-label">Fecha</label><input type="date" className="inp" value={fecha} onChange={e => setFecha(e.target.value)} max={today()} /></div>
        </div>

        <div className="card" style={{ background: "var(--surface2)", padding: "10px 14px" }}>
          <div className="flex-b"><span className="font-bold">Total de la compra</span><span className="font-bold text-accent">{fmt(totalCompra)}</span></div>
        </div>

        <div className="gap-row" style={{ marginTop: 12 }}>
          <button className="btn btn-outline" style={{ flex: 1 }} onClick={onClose}>Cancelar</button>
          <button className="btn btn-accent" style={{ flex: 1.5 }} onClick={confirmar} disabled={guardando}>Confirmar e ingresar</button>
        </div>
      </div>
    </div>
  );
}


/* ════════════ BITÁCORA DE PARCELA ════════════ */
/* Historial de notas de manejo por parcela. Tipos: observación, problema,
   aplicación, decisión, clima, otro. Todas las cuentas reales pueden escribir. */
const TIPOS_BITACORA = [
  { v: "observacion", label: "Observación", emoji: "👁️", color: "blue" },
  { v: "problema", label: "Problema", emoji: "⚠️", color: "red" },
  { v: "aplicacion", label: "Aplicación", emoji: "🧪", color: "green" },
  { v: "decision", label: "Decisión", emoji: "🧭", color: "gold" },
  { v: "clima", label: "Clima", emoji: "🌦️", color: "blue" },
  { v: "otro", label: "Otro", emoji: "📝", color: "gray" },
];

function BitacoraParcela({ data, add, del, parcelaId, session, onClose, embedded }) {
  const [showForm, setShowForm] = useState(false);
  const [filtro, setFiltro] = useState("todas");
  const [form, setForm] = useState({ tipo: "observacion", texto: "", fecha: today() });

  const parcela = (data.parcelas || []).find(p => p.id === parcelaId);
  const puedeEscribir = ["admin", "encargado", "agronomo", "dueno", "finanzas"].includes(session.role);

  const notas = (data.bitacora || [])
    .filter(n => n.parcelaId === parcelaId)
    .filter(n => filtro === "todas" || n.tipo === filtro)
    .sort((a, b) => (b.fecha || "").localeCompare(a.fecha || "") || (b.creadaEn || 0) - (a.creadaEn || 0));

  const tipoInfo = (t) => TIPOS_BITACORA.find(x => x.v === t) || TIPOS_BITACORA[5];

  const guardar = () => {
    if (!form.texto.trim()) { alert("Escribe la nota."); return; }
    const siembra = (data.siembras || []).find(s => s.parcelaId === parcelaId && s.estado !== "cosechada");
    add("bitacora", {
      parcelaId,
      tipo: form.tipo,
      texto: form.texto.trim(),
      fecha: form.fecha || today(),
      creadaEn: Date.now(),
      cultivoNombre: siembra?.cultivoNombre || parcela?.cultivo || "",
      creadaPor: { id: session.id, nombre: session.nombre || "", rol: session.role },
    });
    setForm({ tipo: "observacion", texto: "", fecha: today() });
    setShowForm(false);
  };

  const contenido = (
    <>
      {puedeEscribir && !showForm && (
        <button className="btn btn-accent mb-3" style={{ width: "100%" }} onClick={() => setShowForm(true)}>
          + Nueva nota
        </button>
      )}

      {showForm && (
        <div className="card">
          <div className="card-title">Nueva nota de bitácora</div>
          <div className="form-group">
            <label className="form-label">Tipo</label>
            <div className="gap-row" style={{ flexWrap: "wrap" }}>
              {TIPOS_BITACORA.map(t => (
                <button key={t.v} className={`btn btn-sm ${form.tipo === t.v ? "btn-accent" : "btn-outline"}`}
                        style={{ flex: "1 1 30%" }} onClick={() => setForm(f => ({ ...f, tipo: t.v }))}>
                  {t.emoji} {t.label}
                </button>
              ))}
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">Fecha</label>
            <input type="date" className="inp" value={form.fecha} onChange={e => setForm(f => ({ ...f, fecha: e.target.value }))} max={today()} />
          </div>
          <div className="form-group">
            <label className="form-label">Nota</label>
            <textarea className="inp" style={{ minHeight: 90 }} placeholder="Ej: Se aplicó fungicida en el sector norte porque apareció mancha foliar tras las lluvias..." value={form.texto} onChange={e => setForm(f => ({ ...f, texto: e.target.value }))} />
          </div>
          <div className="gap-row mt-2">
            <button className="btn btn-outline" style={{ flex: 1 }} onClick={() => { setForm({ tipo: "observacion", texto: "", fecha: today() }); setShowForm(false); }}>Cancelar</button>
            <button className="btn btn-accent" style={{ flex: 1.5 }} onClick={guardar}>Guardar nota</button>
          </div>
        </div>
      )}

      {!showForm && (
        <div className="tabs-pill mb-3" style={{ flexWrap: "wrap" }}>
          <button className={`tab-pill${filtro === "todas" ? " active" : ""}`} onClick={() => setFiltro("todas")}>Todas</button>
          {TIPOS_BITACORA.map(t => (
            <button key={t.v} className={`tab-pill${filtro === t.v ? " active" : ""}`} onClick={() => setFiltro(t.v)}>{t.emoji}</button>
          ))}
        </div>
      )}

      {notas.length === 0 && <div className="text-muted text-sm" style={{ textAlign: "center", padding: "28px 0" }}>Sin notas {filtro !== "todas" ? `de tipo "${tipoInfo(filtro).label}"` : "todavía"}</div>}

      {notas.map(n => {
        const ti = tipoInfo(n.tipo);
        return (
          <div key={n.id} className="card" style={{ borderLeft: `3px solid var(--${ti.color === "gray" ? "muted" : ti.color === "red" ? "red" : ti.color === "green" ? "safe" : ti.color === "gold" ? "gold" : "accent"})` }}>
            <div className="flex-b mb-1">
              <span className="text-sm font-bold">{ti.emoji} {ti.label}</span>
              <span className="text-xs text-muted">{n.fecha}</span>
            </div>
            <div className="text-sm" style={{ lineHeight: 1.5, whiteSpace: "pre-wrap" }}>{n.texto}</div>
            <div className="flex-b" style={{ marginTop: 8 }}>
              <span className="text-xs text-muted">{n.creadaPor?.nombre || "—"}{n.cultivoNombre ? ` · ${n.cultivoNombre}` : ""}</span>
              {puedeEscribir && (n.creadaPor?.id === session.id || session.role === "admin") && (
                <button className="btn-ghost text-xs" style={{ color: "var(--red)" }} onClick={() => { if (confirm("¿Borrar esta nota?")) del("bitacora", n.id); }}>borrar</button>
              )}
            </div>
          </div>
        );
      })}
    </>
  );

  // Modo embebido (dentro de otra pantalla): solo el contenido, sin top-bar.
  if (embedded) return <div>{contenido}</div>;

  // Modo pantalla completa
  return (
    <div>
      <div className="top-bar">
        {onClose && <button className="btn-ghost" onClick={onClose}>‹</button>}
        <h2>Bitácora{parcela ? ` · ${parcela.nombre}` : ""} 📒</h2>
      </div>
      <div className="section-pad">{contenido}</div>
    </div>
  );
}

/* ════════════ MODAL: REPORTAR AVANCE DE FASE ════════════ */
/* Permite registrar a mano el % y estado de una fase fenológica
   (lo que se ve en campo: emergencia, brotación, etc.). */
function ReportarAvanceModal({ siembra, etapa, actual, data, add, session, onClose }) {
  const camas = camasSiembra(data, siembra);
  const [modo, setModo] = useState(camas.usaCamas ? "camas" : "porcentaje"); // camas | porcentaje
  const [porcentaje, setPorcentaje] = useState(actual?.porcentaje != null ? String(actual.porcentaje) : "");
  const [camasHechas, setCamasHechas] = useState(actual?.camasHechas != null ? String(actual.camasHechas) : "");
  const [estado, setEstado] = useState(actual?.estado || "en_proceso");
  const [nota, setNota] = useState("");
  const [fecha, setFecha] = useState(today());

  // Calcular el % efectivo según el modo
  const camasNum = parseFloat(camasHechas) || 0;
  const pctDesdeCamas = camas.camasTotal > 0 ? Math.min(100, (camasNum / camas.camasTotal) * 100) : 0;
  const pctEfectivo = modo === "camas" ? pctDesdeCamas : (parseFloat(porcentaje) || 0);
  // Equivalencias para mostrar
  const haEquivalente = camas.hectareas > 0 ? (pctEfectivo / 100) * camas.hectareas : 0;
  const camasEquivalente = camas.camasTotal > 0 ? Math.round((pctEfectivo / 100) * camas.camasTotal) : 0;

  const guardar = () => {
    const pct = Math.max(0, Math.min(100, pctEfectivo));
    add("avances_fase", {
      siembraId: siembra.id,
      parcelaId: siembra.parcelaId,
      etapa,
      porcentaje: Math.round(pct * 10) / 10,
      camasHechas: modo === "camas" ? camasNum : camasEquivalente,
      camasTotal: camas.camasTotal,
      estado,
      nota: nota.trim(),
      fecha: fecha || today(),
      creadaEn: Date.now(),
      reportadoPor: { id: session.id, nombre: session.nombre || "", rol: session.role },
    });
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-sheet" onClick={e => e.stopPropagation()}>
        <div className="flex-b mb-3">
          <h3 style={{ margin: 0, fontSize: 18 }}>Reportar avance</h3>
          <button className="btn-ghost" onClick={onClose} style={{ fontSize: 20 }}>✕</button>
        </div>
        <div className="card" style={{ background: "rgba(126,200,50,.06)", border: "1px solid rgba(126,200,50,.2)" }}>
          <div className="font-bold">{etapa}</div>
          <div className="text-sm text-muted mt-1">{nombreSiembra(siembra)}</div>
          {camas.usaCamas && <div className="text-xs mt-1" style={{ color: "var(--accent)" }}>Total: {fmtN(camas.camasTotal)} camas · {fmtN(camas.hectareas)} ha</div>}
        </div>

        {camas.usaCamas && (
          <div className="tabs-pill" style={{ marginTop: 12 }}>
            <button className={`tab-pill${modo === "camas" ? " active" : ""}`} onClick={() => setModo("camas")}>Por camas</button>
            <button className={`tab-pill${modo === "porcentaje" ? " active" : ""}`} onClick={() => setModo("porcentaje")}>Por %</button>
          </div>
        )}

        {modo === "camas" && camas.usaCamas ? (
          <div className="form-group" style={{ marginTop: 12 }}>
            <label className="form-label">¿Cuántas camas se trabajaron?</label>
            <input type="number" className="inp" min="0" max={camas.camasTotal} placeholder="Ej: 60"
                   value={camasHechas} onChange={e => setCamasHechas(e.target.value)} />
            <div className="text-xs text-muted mt-1">de {fmtN(camas.camasTotal)} camas totales</div>
          </div>
        ) : (
          <div className="form-group" style={{ marginTop: 12 }}>
            <label className="form-label">¿Qué tanto va? ({Math.round(pctEfectivo)}%)</label>
            <input type="range" min="0" max="100" step="5" value={porcentaje || 0}
                   onChange={e => setPorcentaje(e.target.value)} style={{ width: "100%" }} />
            <div className="flex-b text-xs text-muted"><span>0%</span><span>50%</span><span>100%</span></div>
            <input type="number" className="inp mt-2" min="0" max="100" placeholder="O escribe el %"
                   value={porcentaje} onChange={e => setPorcentaje(e.target.value)} />
          </div>
        )}

        {/* Equivalencias en las tres unidades */}
        <div className="card" style={{ background: "var(--surface2)", padding: "10px 14px" }}>
          <div className="flex-b text-sm"><span className="text-muted">Avance</span><span className="font-bold">{Math.round(pctEfectivo)}%</span></div>
          {camas.usaCamas && <div className="flex-b text-sm" style={{ marginTop: 3 }}><span className="text-muted">Camas</span><span className="font-bold">{fmtN(camasEquivalente)} / {fmtN(camas.camasTotal)}</span></div>}
          {camas.hectareas > 0 && <div className="flex-b text-sm" style={{ marginTop: 3 }}><span className="text-muted">Hectáreas</span><span className="font-bold">{haEquivalente.toFixed(2)} / {fmtN(camas.hectareas)} ha</span></div>}
        </div>

        <div className="form-group">
          <label className="form-label">Estado</label>
          <div className="gap-row">
            {[["pendiente", "No iniciada"], ["en_proceso", "En proceso"], ["completada", "Completada"]].map(([v, l]) => (
              <button key={v} className={`btn btn-sm ${estado === v ? "btn-accent" : "btn-outline"}`} style={{ flex: 1 }}
                      onClick={() => {
                        setEstado(v);
                        if (v === "completada") { setPorcentaje("100"); setCamasHechas(String(camas.camasTotal)); }
                        if (v === "pendiente") { setPorcentaje("0"); setCamasHechas("0"); }
                      }}>
                {l}
              </button>
            ))}
          </div>
        </div>

        <div className="form-group">
          <label className="form-label">Fecha del reporte</label>
          <input type="date" className="inp" value={fecha} onChange={e => setFecha(e.target.value)} max={today()} />
        </div>

        <div className="form-group">
          <label className="form-label">Nota (opcional)</label>
          <textarea className="inp" placeholder="Ej: emergencia despareja en el sector bajo..." value={nota} onChange={e => setNota(e.target.value)} />
        </div>

        <div className="gap-row" style={{ marginTop: 12 }}>
          <button className="btn btn-outline" style={{ flex: 1 }} onClick={onClose}>Cancelar</button>
          <button className="btn btn-accent" style={{ flex: 1.5 }} onClick={guardar}>Guardar avance</button>
        </div>
      </div>
    </div>
  );
}

/* ════════════ PANEL DE OPERACIÓN EN VIVO ════════════ */
/* Vista de toda la operación del rancho en este momento:
   qué se está haciendo, dónde, cuánto se lleva, y qué está atrasado. */
function PanelOperacion({ data, onClose, onVerParcela }) {
  const op = panelOperacion(data);

  return (
    <div>
      <div className="top-bar">
        {onClose && <button className="btn-ghost" onClick={onClose}>‹</button>}
        <h2>Operación en vivo 🎯</h2>
      </div>
      <div className="section-pad">
        <div className="text-xs text-muted mb-3" style={{ paddingLeft: 4 }}>
          Refleja lo último reportado en campo. {op.totalSiembrasActivas} siembra(s) activa(s).
        </div>

        {/* COSECHA EN CURSO */}
        {op.cosechas.length > 0 && (
          <div className="card" style={{ background: "rgba(245,166,35,.06)", border: "1px solid rgba(245,166,35,.25)" }}>
            <div className="card-title">🌾 Cosecha en curso</div>
            {op.cosechas.map((c, i) => (
              <div key={i} className="list-item" style={{ cursor: onVerParcela ? "pointer" : "default" }} onClick={() => onVerParcela && onVerParcela(c.siembraId)}>
                <div className="li-body">
                  <div className="li-title">{c.cultivo} · {c.parcela}</div>
                  <div className="li-sub">{c.cosechado > 0 ? `${fmtN(c.cosechado)} ${c.unidad} recolectado` : "Sin registro de cosecha aún"}</div>
                </div>
                <div className="li-right"><div className="li-val">🌾</div></div>
              </div>
            ))}
          </div>
        )}

        {/* EN PROCESO AHORA */}
        <div className="card">
          <div className="card-title">🔴 En proceso ahora</div>
          {op.enProceso.length === 0 && <div className="text-muted text-sm" style={{ padding: "12px 0" }}>Nada reportado en proceso. Si hay labores activas, repórtalas desde el detalle de cada siembra (botón "Reportar avance").</div>}
          {op.enProceso.map((grupo, i) => (
            <div key={i} style={{ marginBottom: 14 }}>
              <div className="font-bold text-sm mb-2" style={{ color: "var(--accent)" }}>{grupo.labor}</div>
              {grupo.items.map((it, j) => (
                <div key={j} className="list-item" style={{ cursor: onVerParcela ? "pointer" : "default", paddingLeft: 8 }} onClick={() => onVerParcela && onVerParcela(it.siembraId)}>
                  <div className="li-body">
                    <div className="li-title" style={{ fontSize: 14 }}>{it.parcela} <span className="text-muted" style={{ fontWeight: 400 }}>· {it.cultivo}</span></div>
                    <div className="progress" style={{ marginTop: 4 }}><div className="progress-fill" style={{ width: `${it.pct}%`, background: it.semaforo === "rojo" ? "var(--red)" : it.semaforo === "amarillo" ? "var(--gold)" : "var(--accent)" }} /></div>
                  </div>
                  <div className="li-right">
                    <div className="li-val">{it.pct}%</div>
                    {it.fuente === "manual" && <div className="li-val-sub">campo</div>}
                  </div>
                </div>
              ))}
            </div>
          ))}
        </div>

        {/* PENDIENTES / ATRASADAS */}
        <div className="card">
          <div className="card-title">⏳ Atrasado o pendiente</div>
          {op.pendientes.length === 0 && <div className="text-muted text-sm" style={{ padding: "12px 0" }}>Nada marcado como atrasado. 👍</div>}
          {op.pendientes.map((grupo, i) => (
            <div key={i} style={{ marginBottom: 14 }}>
              <div className="font-bold text-sm mb-2" style={{ color: "var(--gold)" }}>{grupo.labor}</div>
              {grupo.items.map((it, j) => (
                <div key={j} className="list-item" style={{ cursor: onVerParcela ? "pointer" : "default", paddingLeft: 8 }} onClick={() => onVerParcela && onVerParcela(it.siembraId)}>
                  <div className="li-body">
                    <div className="li-title" style={{ fontSize: 14 }}>{it.parcela} <span className="text-muted" style={{ fontWeight: 400 }}>· {it.cultivo}</span></div>
                    <div className="li-sub">{it.avance > 0 ? `${it.avance}% hecho` : "sin empezar"}</div>
                  </div>
                  <div className="li-right">
                    <span className="badge badge-gold">atrasado</span>
                  </div>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

